import { motion } from "framer-motion";
import { MapPin, Phone, ExternalLink } from "lucide-react";
import { KakaoPlace } from "@/lib/kakao";
import { getShortCategory, getCategoryColor } from "@/hooks/useKakaoSearch";
import PlaceThumbnail from "@/components/PlaceThumbnail";
import LikeButton from "@/components/LikeButton";
import { Theme } from "@/hooks/useThemes";

interface BarCardProps {
  place: KakaoPlace;
  index: number;
  onClick?: () => void;
  themes?: Theme[];
  likeCount?: number;
}

const BarCard = ({ place, index, onClick, themes, likeCount = 0 }: BarCardProps) => {
  const shortCategory = getShortCategory(place.category_name);
  const colorClass = getCategoryColor(shortCategory);

  return (
    <motion.div
      onClick={onClick}
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.04, duration: 0.3 }}
      className="block rounded-xl bg-card p-4 transition-shadow duration-200 cursor-pointer"
      style={{ boxShadow: "var(--shadow-card)" }}
      whileHover={{ boxShadow: "var(--shadow-card-hover)" }}
    >
      <div className="flex gap-3.5">
        {/* Thumbnail with gallery */}
        <PlaceThumbnail
          placeId={place.id}
          placeName={place.place_name}
          className="h-20 w-20 flex-shrink-0 rounded-lg"
          fallbackSize="md"
          enableGallery
        />

        {/* Content */}
        <div className="flex min-w-0 flex-1 flex-col justify-between">
          <div>
            <div className="flex items-start justify-between gap-2">
              <h3 className="text-lg font-semibold text-card-foreground truncate">
                {place.place_name}
              </h3>
              <div className="flex items-center gap-2 flex-shrink-0">
                <LikeButton kakaoPlaceId={place.id} initialCount={likeCount} />
                <ExternalLink className="h-4 w-4 text-muted-foreground" />
              </div>
            </div>
            <p className="mt-0.5 text-sm text-muted-foreground line-clamp-1">
              {place.road_address_name || place.address_name}
            </p>
          </div>

          <div className="mt-2 flex items-center gap-2 flex-wrap">
            <span className={`inline-flex rounded-full px-2 py-0.5 text-xs font-medium ${colorClass}`}>
              {shortCategory}
            </span>
            {themes && themes.length > 0 && themes.map((theme) => (
              <span
                key={theme.id}
                className="inline-flex rounded-full bg-primary/10 px-2 py-0.5 text-xs font-medium text-primary"
              >
                {theme.name}
              </span>
            ))}
            {place.distance && (
              <span className="flex items-center gap-0.5 text-xs text-muted-foreground tabular-nums">
                <MapPin className="h-3 w-3" />
                {parseInt(place.distance) >= 1000
                  ? `${(parseInt(place.distance) / 1000).toFixed(1)}km`
                  : `${place.distance}m`}
              </span>
            )}
            {place.phone && (
              <span className="flex items-center gap-0.5 text-xs text-muted-foreground">
                <Phone className="h-3 w-3" />
                {place.phone}
              </span>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default BarCard;
